#!/usr/bin/env node
// Bundle migrations/*.sql into worker/_migrations_bundle.js so the Worker can
// run them at runtime without needing wrangler d1 migrations apply (which
// won't run on win32/arm64).

const fs = require('fs');
const path = require('path');

const MIGRATIONS_DIR = path.join(__dirname, '..', 'migrations');
const OUTPUT = path.join(__dirname, '..', 'worker', '_migrations_bundle.js');

const files = fs.readdirSync(MIGRATIONS_DIR)
  .filter(f => f.endsWith('.sql'))
  .sort();

const entries = files.map(f => {
  const sql = fs.readFileSync(path.join(MIGRATIONS_DIR, f), 'utf8');
  return { name: f, sql };
});

const body = [
  '// AUTO-GENERATED by scripts/bundle-migrations.js. Do not edit by hand.',
  'export const MIGRATIONS = [',
  ...entries.map(e => {
    const escaped = e.sql.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
    return `  { name: ${JSON.stringify(e.name)}, sql: \`${escaped}\` },`;
  }),
  '];',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, body);
console.log(`Wrote ${OUTPUT} (${entries.length} migrations)`);
